import java.util.*;

public class IntervalScheduling {

    // 1. Merge Overlapping Intervals
    static int[][] merge(int[][] intervals) {
        Arrays.sort(intervals, (a, b) -> a[0] - b[0]); // sort by start
        List<int[]> merged = new ArrayList<>();
        for (int[] interval : intervals) {
            if (merged.isEmpty() || merged.get(merged.size()-1)[1] < interval[0])
                merged.add(interval.clone());
            else
                merged.get(merged.size()-1)[1] = Math.max(merged.get(merged.size()-1)[1], interval[1]);
        }
        return merged.toArray(new int[0][]);
    }

    // 2. Activity Selection — max non-overlapping intervals
    static int activitySelection(int[][] intervals) {
        Arrays.sort(intervals, (a, b) -> a[1] - b[1]); // sort by END time
        int count = 0, lastEnd = Integer.MIN_VALUE;
        for (int[] i : intervals) {
            if (i[0] >= lastEnd) { count++; lastEnd = i[1]; }
        }
        return count;
    }

    // 3. Meeting Rooms II — minimum rooms needed
    static int minMeetingRooms(int[][] intervals) {
        Arrays.sort(intervals, (a, b) -> a[0] - b[0]); // sort by start
        PriorityQueue<Integer> endTimes = new PriorityQueue<>(); // min-heap
        for (int[] meeting : intervals) {
            if (!endTimes.isEmpty() && endTimes.peek() <= meeting[0])
                endTimes.poll(); // reuse room that freed up
            endTimes.offer(meeting[1]);
        }
        return endTimes.size();
    }

    public static void main(String[] args) {
        int[][] intervals = {{1,3},{2,6},{8,10},{15,18}};
        System.out.println(Arrays.deepToString(merge(intervals))); // [[1,6],[8,10],[15,18]]

        int[][] activities = {{1,3},{2,5},{3,9},{6,8}};
        System.out.println(activitySelection(activities)); // 2 (pick [1,3] and [6,8])

        int[][] meetings = {{0,30},{5,10},{15,20}};
        System.out.println(minMeetingRooms(meetings)); // 2
    }
}
